package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.util.List;
import java.util.ArrayList;

class CartTest {

  @Test
  void testCartConstructorAndGetters() {
    List<LineItem> items = new ArrayList<>();
    LineItem item1 = new LineItem("item1", 2, 10.0);
    LineItem item2 = new LineItem("item2", 1, 20.0);
    items.add(item1);
    items.add(item2);

    String buyer = "John Doe";
    String cc = "1234-5678-9012-3456";

    Cart cart = new Cart(items, buyer, cc);

    assertNotNull(cart);
    assertEquals(items, cart.getLineItems());
    assertEquals(buyer, cart.getBuyerName());
    assertEquals(cc, cart.getCreditCard());
  }
}
